function matchGlob(name: string, pattern: string): boolean {
  const regex = '^' + pattern.replace(/[.+^${}()|[\]\\]/g, '\\$&').replace(/\*/g, '.*').replace(/\?/g, '.') + '$'
  try { return new RegExp(regex).test(name) }
  catch { return name.includes(pattern.replace(/\*/g, '')) }
}

function loadGitignorePatterns(startDir: string, rootDir: string): string[] {
  const patterns: string[] = []
  let dir = startDir
  while (true) {
    const gi = resolve(dir, '.gitignore')
    if (existsSync(gi)) {
      try {
        for (const line of readFileSync(gi, 'utf8').split('\n')) {
          const t = line.trim()
          if (t && !t.startsWith('#') && !t.startsWith('!')) patterns.push(t)
        }
      } catch {}
    }
    if (dir === rootDir) break
    const parent = resolve(dir, '..')
    if (parent === dir) break
    dir = parent
  }
  return patterns
}

function matchesGitignore(name: string, patterns: string[]): boolean {
  for (const p of patterns) {
    let clean = p.endsWith('/') ? p.slice(0, -1) : p
    if (clean.includes('*') || clean.includes('?')) {
      if (matchGlob(name, clean)) return true
    } else if (name === clean) return true
  }
  return false
}

