function tryFd(args: string[], cwd: string): { result: any, binary: string | null, warning: string | null } {
  const toolDir = resolve(cwd, '.opencode/tools/bin')
  const binaries = ['fd', resolve(toolDir, 'fd'), '/opt/homebrew/bin/fd', '/usr/local/bin/fd']
  for (const bin of binaries) {
    const result = spawnSync(bin, args, {cwd, encoding:'utf8', maxBuffer:1024*1024*5, timeout:15000})
    if (result.error) {
      if (result.error.message?.includes('ENOENT')) continue
      return {result, binary: bin, warning: `fd at ${bin} failed: ${result.error.message}`}
    }
    if (result.status === 0) return {result, binary: bin, warning: null}
    if (result.status !== 0) return {result, binary: bin, warning: `fd at ${bin} exited with status ${result.status}`}
  }
  return {result: null, binary: null, warning: null}
}

function walkNative(searchPath: string, opts: {maxResults:number,maxDepth:number,typeFilter:string|undefined,pattern:string|undefined,newerThanMs:number,includeSizes:boolean,ignorePatterns:string[]}) {
  const results: any[] = []
  let totalFound = 0, dirCount = 0
  const byExt: Record<string,number> = {}
  const needStat = opts.newerThanMs > 0 || opts.includeSizes
  const cutoff = Date.now() - opts.newerThanMs
  function walk(dir: string, depth: number) {
    if (results.length >= opts.maxResults) return
    if (opts.maxDepth > 0 && depth > opts.maxDepth) return
    let entries: any[]
    try { entries = readdirSync(dir, {withFileTypes:true}) }
    catch { return }
    for (const e of entries) {
      if (results.length >= opts.maxResults) break
      if (matchesGitignore(e.name, opts.ignorePatterns)) continue
      if (e.isSymbolicLink?.()) continue
      if (e.isDirectory?.()) {
        if (opts.typeFilter !== 'file') {
          if (!opts.pattern || matchGlob(e.name, opts.pattern)) {
            totalFound++
            if (results.length < opts.maxResults) { results.push({path:relative(searchPath,resolve(dir,e.name)),type:'directory'}); dirCount++ }
          }
        }
        walk(resolve(dir, e.name), depth + 1)
        continue
      }
      if (e.isFile?.()) {
        if (opts.typeFilter === 'directory') continue
        if (opts.pattern && !matchGlob(e.name, opts.pattern)) continue
        let st: any = null
        if (needStat) { try { st = statSync(resolve(dir, e.name)) } catch { continue } }
        if (st && opts.newerThanMs > 0 && st.mtimeMs < cutoff) continue
        totalFound++
        if (results.length < opts.maxResults) {
          const entry: any = {path:relative(searchPath,resolve(dir,e.name)),type:'file'}
          if (st) {
            if (opts.includeSizes) entry.size_bytes = st.size
            if (opts.newerThanMs > 0) entry.modified_seconds_ago = Math.floor((Date.now()-st.mtimeMs)/1000)
          }
          results.push(entry)
          const ext = e.name.includes('.') ? '.'+e.name.split('.').pop()! : '(no extension)'
          byExt[ext] = (byExt[ext]||0) + 1
        }
      }
    }
  }
  walk(searchPath, 0)
  return {results, totalFound, dirCount, byExt}
}
